{
  "analysis": "The task is to fill in placeholders in a Word template document using data from a JSON file. The template contains placeholders like {{CANDIDATE_FULL_NAME}} and {{POSITION}}. There's also a conditional section that should only be included if RELOCATION_PACKAGE is set to 'Yes'. The goal is to create a filled-in offer letter at /root/offer_letter_filled.docx.",
  "plan": [
    "Load the employee_data.json file to get the necessary information for filling the placeholders",
    "Load the offer_letter_template.docx template document",
    "Iterate through the document's paragraphs, runs, tables, headers, and footers",
    "Replace each placeholder with the corresponding value from employee_data.json",
    "Handle the conditional section by checking the RELOCATION_PACKAGE value and including/excluding it accordingly",
    "Save the filled document to /root/offer_letter_filled.docx"
  ],
  "commands": [
    {
      "keystrokes": "import json
with open('employee_data.json') as f:
    employee_data = json.load(f)
",
      "duration": 0.1
    },
    {
      "keystrokes": "from docx import Document
doc = Document('offer_letter_template.docx')
",
      "duration": 0.1
    },
    {
      "keystrokes": "def replace_placeholders(doc, data):
    for para in doc.paragraphs:
        for key, value in data.items():
            placeholder = '{{' + key + '}}'
            if placeholder in para.text:
                para.text = para.text.replace(placeholder, value)
    for table in doc.tables:
        for row in table.rows:
            for cell in row.cells:
                for para in cell.paragraphs:
                    for key, value in data.items():
                        placeholder = '{{' + key + '}}'
                        if placeholder in para.text:
                            para.text = para.text.replace(placeholder, value)
    for section in doc.sections:
        for para in section.header.paragraphs:
            for key, value in data.items():
                placeholder = '{{' + key + '}}'
                if placeholder in para.text:
                    para.text = para.text.replace(placeholder, value)
        for para in section.footer.paragraphs:
            for key, value in data.items():
                placeholder = '{{' + key + '}}'
                if placeholder in para.text:
                    para.text = para.text.replace(placeholder, value)
",
      "duration": 0.1
    },
    {
      "keystrokes": "replace_placeholders(doc, employee_data)
",
      "duration": 0.1
    },
    {
      "keystrokes": "if employee_data.get('RELOCATION_PACKAGE', 'No') == 'Yes':
    for para in doc.paragraphs:
        if '{{IF_RELOCATION}}' in para.text:
            para.text = para.text.replace('{{IF_RELOCATION}}', '')
        if '{{END_IF_RELOCATION}}' in para.text:
            para.text = para.text.replace('{{END_IF_RELOCATION}}', '')
",
      "duration": 0.1
    },
    {
      "keystrokes": "doc.save('/root/offer_letter_filled.docx')
",
      "duration": 0.1
    }
  ],
  "task_complete": true
}
